export async function fetchPubMedResearch() {
  const query = "personality psychology MBTI";
  const url = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&retmode=json&retmax=5&term=${encodeURIComponent(
    query
  )}`;

  const searchResponse = await fetch(url);
  const searchData = await searchResponse.json();

  const ids = searchData.esearchresult.idlist;
  if (!ids.length) return [];

  const summaryUrl = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esummary.fcgi?db=pubmed&retmode=json&id=${ids.join(
    ","
  )}`;

  const summaryResponse = await fetch(summaryUrl);
  const summaryData = await summaryResponse.json();

  return ids.map((id) => {
    const item = summaryData.result[id];
    return {
      title: item.title,
      source: "PubMed",
      link: `https://pubmed.ncbi.nlm.nih.gov/${id}/`,
    };
  });
}
